                else if (piece.piece === '炮') {
                    // 简化：假设炮可以攻击同一行/列
                    if (piece.x === x || piece.y === y) {
                        return true;
                    }
                }
            }
            return false;
        }

        // AI 移动棋子
        function moveAI(ju) {
            if (!ju.setup.otherPieces || ju.setup.otherPieces.length === 0) {
                return null; // 没有敌方棋子
            }

            // 找到可以攻击到马的敌方棋子并移动
            const enemyPieces = ju.setup.otherPieces;
            const horsePos = currentHorsePos;

            // 简单 AI：移动第一个可以更接近马的棋子
            for (let i = 0; i < enemyPieces.length; i++) {
                const piece = enemyPieces[i];

                // 车的移动：直线向马靠近
                if (piece.piece === '车') {
                    let newX = piece.x;
                    let newY = piece.y;

                    // 向马靠近一步
                    if (piece.x < horsePos.x) newX++;
                    else if (piece.x > horsePos.x) newX--;
                    else if (piece.y < horsePos.y) newY++;
                    else if (piece.y > horsePos.y) newY--;

                    // 更新棋子位置
                    if (newX !== piece.x || newY !== piece.y) {
                        piece.x = newX;
                        piece.y = newY;
